.twyne-editor .ProseMirror img.ProseMirror-selectednode {
  outline: 2px solid var(--color-vermilion);
}

.twyne-editor .ProseMirror table {
  border-collapse: collapse;
  width: 100%;
  margin: 1em 0;
  font-family: var(--font-sans);
  font-size: 0.95rem;
}

.twyne-editor .ProseMirror table td,
.twyne-editor .ProseMirror table th {
  border: 1px solid var(--color-paper-3);
  padding: 0.55em 0.8em;
  text-align: left;
}

.twyne-editor .ProseMirror table th {
  background: var(--color-paper-2);
  font-weight: 700;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
}

.twyne-editor .ProseMirror .columnResizorHandle {
  background-color: var(--color-vermilion);
}

.twyne-editor .ProseMirror mark {
  background: linear-gradient(transparent 60%, rgba(212, 160, 23, 0.45) 60%);
  padding: 0;
  border-radius: 0;
}

.twyne-editor .ProseMirror hr {
  border: none;
  text-align: center;
  margin: 2em 0;
}
.twyne-editor .ProseMirror hr::before {
  content: "❦";
  color: var(--color-vermilion);
  font-size: 1.1rem;
  letter-spacing: 0.5em;
}

.twyne-editor .ProseMirror .is-editor-empty:first-child::before {
  content: attr(data-placeholder);
  float: left;
  color: var(--color-ink-muted);
  pointer-events: none;
  height: 0;
  font-style: italic;
  font-family: var(--font-display);
}

/* Citation: a hot-pencil underline */
.twyne-editor .ProseMirror .citation-mark {
  background-color: rgba(92, 107, 192, 0.1);
  border-bottom: 2px dotted var(--color-periwinkle);
  cursor: pointer;
}

/* Comment: marginalia highlight */
.twyne-editor .ProseMirror .comment-mark {
  background-color: rgba(212, 160, 23, 0.18);
  border-bottom: 2px solid var(--color-mustard);
  cursor: pointer;
}

/* Persona feedback line decoration */
.persona-feedback-card {
  border-left-width: 3px;
}

/* Drag-over overlay */
.drag-overlay {
  position: fixed;
  inset: 0;
  background: rgba(193, 39, 45, 0.07);
  border: 2px dashed var(--color-vermilion);
  z-index: var(--z-overlay);
  display: flex;
  align-items: center;
  justify-content: center;
  pointer-events: none;
}

.drag-overlay span {
  background: var(--color-vermilion);
  color: var(--color-paper);
  padding: 0.75em 1.5em;
  border-radius: 2px;
  font-family: var(--font-typewriter);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-size: 0.75rem;
}

/* Scrollbar for panels */
.panel-scroll {
  overflow-y: auto;
  max-height: calc(100vh - 3rem);
}

.sidebar-transition {
  transition:
    width 0.2s ease,
    opacity 0.2s ease,
    transform 0.2s ease;
}

.focus-ring:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 2px;
}

/* Rubric score animation — fills from 0 to the inline width */
@keyframes rubric-fill {
  from {
    width: 0;
  }
}

.rubric-bar {
  animation: rubric-fill 0.6s ease-out forwards;
}

/* A subtle hand-set wobble for the masthead — French Dispatch nod */
@keyframes presswobble {
  0%,
  100% {
    transform: translate(0, 0) rotate(0deg);
  }
  25% {
    transform: translate(0.2px, -0.1px) rotate(-0.05deg);
  }
  75% {
    transform: translate(-0.15px, 0.1px) rotate(0.05deg);
  }
}
.press {
  animation: presswobble 4s ease-in-out infinite;
  display: inline-block;
}

/* Editorial button — a small set, hot-press feel */
.btn-press {
  font-family: var(--font-typewriter);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-size: 0.7rem;
  padding: 0.55rem 1rem;
  background: var(--color-ink);
  color: var(--color-paper);
  border: 1px solid var(--color-ink);
  border-radius: 2px;
  transition:
    transform 0.1s ease,
    background 0.15s ease;
  cursor: pointer;
}
.btn-press:hover {
  background: var(--color-vermilion-2);
  border-color: var(--color-vermilion-2);
}
.btn-press:active {
  transform: translateY(1px);
}
.btn-press:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.btn-paper {
  font-family: var(--font-sans);
  font-size: 0.75rem;
  font-weight: 600;
  padding: 0.45rem 0.9rem;
  background: var(--color-paper-soft);
  color: var(--color-ink);
  border: 1px solid var(--color-paper-3);
  border-radius: 2px;
  transition: background 0.15s ease;
  cursor: pointer;
}
.btn-paper:hover {
  background: var(--color-paper-2);
}

.btn-press:focus-visible,
.btn-paper:focus-visible,
.landing-button:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 2px;
}

/* Small icon-only control — consistent hit target + accessible focus */
.icon-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 1.75rem;
  min-height: 1.75rem;
  border-radius: 2px;
  color: var(--color-ink-muted);
  transition:
    color 0.15s ease,
    background 0.15s ease;
  cursor: pointer;
}
.icon-btn:hover {
  color: var(--color-ink);
  background: var(--color-paper-2);
}
.icon-btn:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 1px;
}

/* Editor toolbar button — supports a pressed/active state */
.tool-btn {
  padding: 0.25rem 0.5rem;
  font-size: 0.875rem;
  color: var(--color-ink-light);
  border-radius: 2px;
  transition:
    color 0.15s ease,
    background 0.15s ease;
  cursor: pointer;
}
.tool-btn:hover {
  color: var(--color-vermilion);
  background: var(--color-paper-soft);
}
.tool-btn[aria-pressed="true"] {
  color: var(--color-vermilion);
  background: var(--color-paper-2);
  box-shadow: inset 0 -2px 0 var(--color-vermilion);
}
.tool-btn:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: -2px;
}

/* Editorial form controls — shared input vocabulary */
.field-label {
  display: block;
  font-family: var(--font-typewriter);
  font-size: 0.625rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-light);
  margin-bottom: 0.35rem;
}
.field-input {
  width: 100%;
  padding: 0.5rem 0.75rem;
  font-family: var(--font-serif);
  font-size: 0.875rem;
  color: var(--color-ink);
  background: var(--color-paper-soft);
  border: 1px solid var(--color-paper-3);
  border-radius: 2px;
}
.field-input::placeholder {
  color: var(--color-ink-muted);
  font-style: italic;
}
.field-input:focus {
  outline: none;
  border-color: var(--color-vermilion);
}
.field-input:focus-visible {
  outline: 1px solid var(--color-vermilion);
  outline-offset: 0;
}

/* Inline error note — letterpress slip, not a toast */
.error-slip {
  padding: 0.6rem 0.8rem;
  border: 1px solid var(--color-vermilion);
  background: rgba(193, 39, 45, 0.05);
  border-radius: 2px;
  color: var(--color-vermilion-2);
  font-family: var(--font-serif);
  font-size: 0.8125rem;
  line-height: 1.45;
}

/* Landing page surfaces */
.landing-page {
  position: relative;
  overflow: clip;
  background:
    radial-gradient(
      circle at top left,
      rgba(193, 39, 45, 0.08),
      transparent 26%
    ),
    radial-gradient(
      circle at 82% 18%,
      rgba(92, 107, 192, 0.08),
      transparent 18%
    ),
    linear-gradient(180deg, #f7f1e2 0%, #f4ecd8 34%, #f2e7cf 100%);
}

.landing-page::before {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background-image:
    radial-gradient(
      circle at 15% 20%,
      rgba(31, 27, 22, 0.025) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 70% 40%,
      rgba(31, 27, 22, 0.02) 0,
      transparent 1px
    ),
    radial-gradient(
      circle at 85% 78%,
      rgba(31, 27, 22, 0.015) 0,
      transparent 1px
    );
  background-size:
    9px 9px,
    11px 11px,
    13px 13px;
  opacity: 0.45;
}

.landing-shell {
  position: relative;
  z-index: 1;
  width: min(1440px, calc(100% - 1.5rem));
  margin: 0 auto;
}

.landing-frame {
  background: rgba(250, 243, 223, 0.7);
  border: 1px solid rgba(122, 30, 34, 0.08);
  border-radius: 28px;
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 40px 80px -52px rgba(31, 27, 22, 0.28);
  backdrop-filter: blur(10px);
}

.landing-kicker {
  font-family: var(--font-typewriter);
  letter-spacing: 0.28em;
  text-transform: uppercase;
  font-size: 0.7rem;
  color: var(--color-ink-muted);
}

.landing-title {
  font-family: var(--font-display);
  color: var(--color-ink);
  letter-spacing: -0.03em;
}

.landing-deck {
  font-family: var(--font-serif);
  color: var(--color-ink-light);
  line-height: 1.7;
}

.landing-button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.55rem;
  min-height: 2.8rem;
  padding: 0.7rem 1.4rem;
  border-radius: 999px;
  border: 1px solid transparent;
  font-family: var(--font-typewriter);
  font-size: 0.75rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  transition:
    transform 0.15s ease,
    background 0.15s ease,
    border-color 0.15s ease;
}

.landing-button:hover {
  transform: translateY(-1px);
}

.landing-button.primary {
  background: var(--color-vermilion);
  color: var(--color-paper);
  border-color: var(--color-vermilion);
}

.landing-button.primary:hover {
  background: var(--color-vermilion-2);
  border-color: var(--color-vermilion-2);
}

.landing-button.secondary {
  background: transparent;
  color: var(--color-ink);
  border-color: rgba(31, 27, 22, 0.28);
}

.landing-chip {
  display: inline-flex;
  align-items: center;
  gap: 0.4rem;
  padding: 0.4rem 0.85rem;
  border-radius: 999px;
  border: 1px solid rgba(31, 27, 22, 0.1);
  background: rgba(250, 243, 223, 0.55);
  font-family: var(--font-typewriter);
  font-size: 0.64rem;
…1796 tokens truncated…from {
    opacity: 0;
    transform: translateY(16px);
  }
  to {
    opacity: 1;
    transform: none;
  }
}
.landing-rise,
.landing-rise-2,
.landing-rise-3 {
  animation: landing-rise 0.7s cubic-bezier(0.22, 1, 0.36, 1) both;
}
.landing-rise-2 {
  animation-delay: 0.12s;
}
.landing-rise-3 {
  animation-delay: 0.24s;
}
@media (prefers-reduced-motion: reduce) {
  .landing-rise,
  .landing-rise-2,
  .landing-rise-3 {
    animation: none;
  }
}

/* ─────────────────────────────────────────────────────────────
 * Paper primitives — shared across landing variants
 *   .paper-sheet      : aged newsprint with grain + foxing
 *   .paper-foxed      : adds little browned spots
 *   .paper-deckle     : torn/deckle bottom edge
 *   .paper-rule       : thin double rule, ink
 *   .ink-bleed        : letterpress-style soft ink halo
 *   .stamp-tilt       : rubber-stamp rotation utility
 * ───────────────────────────────────────────────────────────── */
.paper-sheet {
  position: relative;
  background-color: #f5ecd6;
  background-image:
    radial-gradient(
      circle at 18% 22%,
      rgba(122, 84, 38, 0.06) 0,
      transparent 38%
    ),
    radial-gradient(
      circle at 82% 78%,
      rgba(122, 84, 38, 0.05) 0,
      transparent 42%
    ),
    radial-gradient(
      circle at 50% 50%,
      rgba(255, 248, 220, 0.6) 0,
      transparent 60%
    ),
    repeating-linear-gradient(
      135deg,
      rgba(31, 27, 22, 0.018) 0 2px,
      transparent 2px 6px
    ),
    radial-gradient(
      circle at 30% 40%,
      rgba(31, 27, 22, 0.04) 0 1px,
      transparent 1.4px
    ),
    radial-gradient(
      circle at 70% 60%,
      rgba(31, 27, 22, 0.035) 0 1px,
      transparent 1.4px
    ),
    radial-gradient(
      circle at 15% 85%,
      rgba(31, 27, 22, 0.03) 0 1px,
      transparent 1.4px
    );
  background-size:
    auto,
    auto,
    auto,
    auto,
    5px 5px,
    7px 7px,
    9px 9px;
  box-shadow:
    inset 0 0 60px rgba(122, 84, 38, 0.08),
    inset 0 0 0 1px rgba(31, 27, 22, 0.04);
}
.paper-foxed::after {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background-image:
    radial-gradient(
      circle at 12% 18%,
      rgba(140, 90, 36, 0.18) 0 1.2px,
      transparent 2.5px
    ),
    radial-gradient(
      circle at 88% 32%,
      rgba(140, 90, 36, 0.16) 0 0.9px,
      transparent 2px
    ),
    radial-gradient(
      circle at 24% 78%,
      rgba(140, 90, 36, 0.14) 0 1.4px,
      transparent 2.8px
    ),
    radial-gradient(
      circle at 76% 88%,
      rgba(140, 90, 36, 0.18) 0 1px,
      transparent 2.2px
    ),
    radial-gradient(
      circle at 50% 50%,
      rgba(140, 90, 36, 0.12) 0 0.8px,
      transparent 2px
    );
  opacity: 0.7;
  mix-blend-mode: multiply;
}
.paper-deckle {
  --deckle-color: #f5ecd6;
  position: relative;
}
.paper-deckle::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: -10px;
  height: 14px;
  background:
    radial-gradient(circle at 5% 0, var(--deckle-color) 6px, transparent 7px) 0
      0/14px 14px repeat-x,
    radial-gradient(circle at 50% 6px, var(--deckle-color) 8px, transparent 9px)
      7px 0/22px 14px repeat-x;
  filter: drop-shadow(0 2px 1px rgba(31, 27, 22, 0.08));
}
.paper-rule {
  border: 0;
  height: 5px;
  background: linear-gradient(
    to bottom,
    var(--color-ink) 0 1px,
    transparent 1px 3px,
    var(--color-ink) 3px 4px,
    transparent 4px
  );
  opacity: 0.65;
}
.paper-rule.thin {
  height: 1px;
  background: var(--color-ink);
  opacity: 0.35;
}
.ink-bleed {
  text-shadow:
    0 0 0.4px currentColor,
    0.3px 0.3px 0 rgba(31, 27, 22, 0.18),
    -0.2px -0.2px 0 rgba(31, 27, 22, 0.08);
}
.stamp-tilt {
  transform: rotate(-6deg);
}
.stamp-tilt-r {
  transform: rotate(4deg);
}

/* Halftone — old printed-image dot pattern */
.halftone {
  background-image: radial-gradient(
    circle,
    rgba(31, 27, 22, 0.55) 0 1px,
    transparent 1.4px
  );
  background-size: 4px 4px;
}

/* Variant switcher bar (shown above the landing) */
.variant-bar {
  position: fixed;
  top: 12px;
  right: 12px;
  z-index: 100;
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 6px;
  border-radius: 999px;
  background: rgba(245, 236, 214, 0.92);
  border: 1px solid rgba(31, 27, 22, 0.12);
  box-shadow: 0 12px 30px -18px rgba(31, 27, 22, 0.4);
  font-family: var(--font-typewriter);
  font-size: 0.65rem;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}
.variant-bar a {
  padding: 6px 12px;
  border-radius: 999px;
  color: var(--color-ink-muted);
  text-decoration: none;
}
.variant-bar a.active {
  background: var(--color-ink);
  color: var(--color-paper);
}

/* ─── Variant A — Broadsheet ─────────────────────────────── */
.broadsheet {
  background-color: #f5ecd6;
  min-height: 100vh;
}
.broadsheet-page {
  max-width: 1200px;
  margin: 0 auto;
  padding: 2rem 2.5rem 4rem;
  position: relative;
}
.broadsheet-masthead {
  text-align: center;
  border-top: 6px double var(--color-ink);
  border-bottom: 6px double var(--color-ink);
  padding: 1.5rem 0 1.25rem;
  margin-bottom: 1rem;
}
.broadsheet-nameplate {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(4rem, 12vw, 9rem);
  line-height: 0.85;
  letter-spacing: 0.05em;
  color: var(--color-ink);
  margin: 0.4rem 0 0.5rem;
}
.broadsheet-dateline {
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  border-bottom: 1px solid var(--color-ink);
  padding: 0.5rem 0.5rem;
  margin-bottom: 1.25rem;
}
.broadsheet-headline {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(2.5rem, 5.5vw, 4.5rem);
  line-height: 1.02;
  letter-spacing: -0.02em;
  color: var(--color-ink);
  text-align: center;
}
.broadsheet-deck {
  font-family: var(--font-display);
  font-style: italic;
  font-weight: 400;
  font-size: clamp(1.1rem, 1.6vw, 1.4rem);
  line-height: 1.35;
  text-align: center;
  color: var(--color-ink-light);
  max-width: 38rem;
  margin: 1rem auto 0;
}
.broadsheet-byline {
  text-align: center;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.3em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  margin-top: 1.25rem;
}
.broadsheet-cols {
  column-count: 3;
  column-gap: 2.25rem;
  column-rule: 1px solid rgba(31, 27, 22, 0.18);
  font-family: var(--font-serif);
  font-size: 1rem;
  line-height: 1.7;
  text-align: justify;
  hyphens: auto;
  -webkit-hyphens: auto;
  color: var(--color-ink);
  margin-top: 2.25rem;
}
.broadsheet-cols p {
  margin: 0 0 0.85em;
}
.broadsheet-cols p:first-of-type::first-letter {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 4em;
  float: left;
  line-height: 0.85;
  margin: 0.05em 0.1em -0.05em 0;
  color: var(--color-vermilion);
}
.broadsheet-section-rule {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin: 2.5rem 0 1.5rem;
}
.broadsheet-section-rule .rule {
  flex: 1;
  height: 1px;
  background: var(--color-ink);
}
.broadsheet-section-rule .label {
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.36em;
  text-transform: uppercase;
  color: var(--color-ink);
  white-space: nowrap;
}
.broadsheet-bulletin {
  border-top: 3px double var(--color-ink);
  border-bottom: 3px double var(--color-ink);
  padding: 1.25rem 0;
  margin-top: 1rem;
}
.broadsheet-bulletin h3 {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.4rem;
  margin: 0 0 0.3rem;
  letter-spacing: -0.01em;
}
.broadsheet-bulletin p {
  font-family: var(--font-serif);
  font-size: 0.95rem;
  line-height: 1.55;
  color: var(--color-ink-light);
  margin: 0;
}
.broadsheet-cta {
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.85rem 1.5rem;
  background: var(--color-ink);
  color: var(--color-paper);
  font-family: var(--font-typewriter);
  font-size: 0.8125rem;
  letter-spacing: 0.18em;
  text-transform: uppercase;
  border: 0;
  cursor: pointer;
}
.broadsheet-cta:hover {
  background: var(--color-vermilion);
}
.broadsheet-cta:focus-visible {
  outline: 2px solid var(--color-vermilion);
  outline-offset: 2px;
}
.broadsheet-cta.secondary {
  background: transparent;
  color: var(--color-ink);
  border: 1px solid var(--color-ink);
}

/* ─── Variant B — Letterpress Quarterly ───────────────────── */
.quarterly {
  min-height: 100vh;
  background: radial-gradient(
    ellipse at top,
    #f8efd9 0%,
    #efe3c4 60%,
    #e6d8b3 100%
  );
  padding: 3rem 1rem 5rem;
}
.quarterly-cover {
  max-width: 720px;
  margin: 0 auto;
  padding: 4.5rem 3rem 5rem;
  text-align: center;
  position: relative;
  border: 1px solid rgba(31, 27, 22, 0.18);
  background: rgba(248, 240, 218, 0.85);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.7) inset,
    0 60px 100px -60px rgba(31, 27, 22, 0.5);
}
.quarterly-cover::before {
  content: "";
  position: absolute;
  inset: 16px;
  border: 1px solid rgba(31, 27, 22, 0.22);
  pointer-events: none;
}
.quarterly-edition {
  font-family: var(--font-typewriter);
  font-size: 0.75rem;
  letter-spacing: 0.36em;
  text-transform: uppercase;
  color: var(--color-vermilion);
  margin: 0;
}
.quarterly-title {
  font-family: var(--font-display);
  font-weight: 700;
  font-style: italic;
  font-size: clamp(3.5rem, 8vw, 6rem);
  line-height: 0.9;
  letter-spacing: -0.02em;
  color: var(--color-ink);
  margin: 1rem 0 0.4rem;
}
.quarterly-subtitle {
  font-family: var(--font-display);
  font-weight: 400;
  font-size: clamp(1.25rem, 2.4vw, 1.75rem);
  line-height: 1.25;
  color: var(--color-ink-light);
  margin: 0.5rem auto 0;
  max-width: 28rem;
}
.quarterly-rule {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  margin: 2rem 0;
  color: var(--color-vermilion);
}
.quarterly-rule .line {
  flex: 0 0 60px;
  height: 1px;
  background: var(--color-ink);
}
.quarterly-rule .ornament {
  font-family: var(--font-display);
  font-size: 1.4rem;
}
.quarterly-deck {
  font-family: var(--font-serif);
  font-size: 1.05rem;
  line-height: 1.75;
  color: var(--color-ink-light);
  max-width: 32rem;
  margin: 0 auto;
}
.quarterly-buttons {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 1rem;
  margin-top: 2.25rem;
}
.quarterly-button {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.95rem 1.6rem;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  border: 1px solid var(--color-ink);
  background: var(--color-ink);
  color: var(--color-paper);
  cursor: pointer;
}
.quarterly-button.ghost {
  background: transparent;
  color: var(--color-ink);
}
.quarterly-button:hover {
  background: var(--color-vermilion);
  border-color: var(--color-vermilion);
  color: var(--color-paper);
}
.quarterly-section {
  max-width: 720px;
  margin: 4rem auto 0;
  text-align: center;
}
.quarterly-section h2 {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: clamp(1.6rem, 3vw, 2.25rem);
  letter-spacing: -0.01em;
  color: var(--color-ink);
  margin: 0 0 0.5rem;
}
.quarterly-section .kicker {
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.34em;
  text-transform: uppercase;
  color: var(--color-vermilion);
  margin-bottom: 0.5rem;
}
.quarterly-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 2rem 2.5rem;
  margin-top: 3rem;
  text-align: left;
}
.quarterly-entry {
  position: relative;
  padding-left: 2.5rem;
}
.quarterly-entry .numeral {
  position: absolute;
  left: 0;
  top: -0.1rem;
  font-family: var(--font-display);
  font-size: 1.6rem;
  color: var(--color-vermilion);
  font-style: italic;
}
.quarterly-entry h3 {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 1.2rem;
  margin: 0 0 0.35rem;
  color: var(--color-ink);
}
.quarterly-entry p {
  font-family: var(--font-serif);
  font-size: 0.92rem;
  line-height: 1.65;
  color: var(--color-ink-light);
  margin: 0;
}

/* ─── Variant C — Telegram Gazette ────────────────────────── */
.telegram {
  min-height: 100vh;
  background: #f4ecd8;
  padding: 2.5rem 1.5rem 4rem;
  font-family: var(--font-typewriter);
}
.telegram-sheet {
  max-width: 760px;
  margin: 0 auto;
  background: #fbf4dc;
  padding: 3rem 3rem 3.5rem;
  border: 1px solid rgba(31, 27, 22, 0.22);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.6) inset,
    0 30px 60px -40px rgba(31, 27, 22, 0.45);
  position: relative;
}
.telegram-stamp {
  position: absolute;
  top: 1.5rem;
  right: 1.5rem;
  font-family: var(--font-typewriter);
  font-size: 0.6rem;
  letter-spacing: 0.3em;
  border: 2px solid var(--color-vermilion);
  color: var(--color-vermilion);
  padding: 0.35rem 0.6rem;
  text-transform: uppercase;
  transform: rotate(-7deg);
  background: rgba(193, 39, 45, 0.04);
}
.telegram-header {
  text-align: center;
  border-bottom: 2px solid var(--color-ink);
  padding-bottom: 1rem;
  margin-bottom: 1.5rem;
}
.telegram-header .from {
  font-size: 0.65rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
}
.telegram-header h1 {
  font-family: var(--font-typewriter);
  font-size: clamp(1.6rem, 3.5vw, 2.4rem);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  margin: 0.4rem 0 0;
  color: var(--color-ink);
}
.telegram-meta {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.5rem 1.5rem;
  font-size: 0.62rem;
  letter-spacing: 0.22em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  margin-bottom: 2rem;
  padding-bottom: 1rem;
  border-bottom: 1px dashed rgba(31, 27, 22, 0.3);
}
.telegram-meta strong {
  display: block;
  color: var(--color-ink);
  font-weight: 700;
  font-size: 0.8rem;
  letter-spacing: 0.14em;
  margin-top: 0.15rem;
}
.telegram-body {
  font-family: var(--font-typewriter);
  font-size: 1.05rem;
  line-height: 1.85;
  color: var(--color-ink);
  letter-spacing: 0.005em;
}
.telegram-body p {
  margin: 0 0 1.25em;
}
.telegram-body p::before {
  content: "";
}
.telegram-stop {
  display: inline-block;
  font-weight: 700;
  letter-spacing: 0.24em;
  color: var(--color-vermilion);
  margin: 0 0.35em;
}
.telegram-list {
  list-style: none;
  margin: 1.5rem 0;
  padding: 0;
  display: grid;
  gap: 0.6rem;
}
.telegram-list li {
  display: grid;
  grid-template-columns: auto 1fr;
  gap: 0.85rem;
  font-size: 0.95rem;
  letter-spacing: 0.01em;
}
.telegram-list .num {
  color: var(--color-vermilion);
  font-weight: 700;
}
.telegram-actions {
  margin-top: 2.25rem;
  padding-top: 1.25rem;
  border-top: 2px solid var(--color-ink);
  display: flex;
  flex-wrap: wrap;
  gap: 0.85rem;
  align-items: center;
  justify-content: space-between;
}
.telegram-button {
  display: inline-flex;
  align-items: center;
  gap: 0.6rem;
  padding: 0.85rem 1.4rem;
  font-family: var(--font-typewriter);
  font-size: 0.7rem;
  letter-spacing: 0.28em;
  text-transform: uppercase;
  background: var(--color-ink);
  color: var(--color-paper);
  border: 0;
  cursor: pointer;
}
.telegram-button.ghost {
  background: transparent;
  color: var(--color-ink);
  border: 1px dashed var(--color-ink);
}
.telegram-signoff {
  text-align: right;
  font-size: 0.68rem;
  letter-spacing: 0.32em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
  margin-top: 1.5rem;
}

/* ── Reduced motion ──────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .press,
  .animate-spin,
  .feedback-enter {
    animation: none !important;
  }
  /* The bar keeps its final inline width; only the fill sweep is dropped */
  .rubric-bar {
    animation: none !important;
  }
  .sidebar-transition,
  .landing-button,
  .landing-feature-card,
  .portrait {
    transition: none !important;
  }
  .landing-button:hover,
  .landing-feature-card:hover,
  .portrait:hover {
    transform: none !important;
  }
}

/* ── Legal & document pages ──────────────────────────────────
   Rendered through <LegalPage>. The body lives inside a scrollable
   "manuscript" frame (.legal-editor) that echoes the landing editor;
   these rules are global because the document text is projected through
   a <Slot> and therefore cannot be reached by component-scoped styles. */
.legal-editor {
  border: 2px double var(--color-paper-3);
  border-radius: 4px;
  background: var(--color-editor-bg);
  box-shadow:
    0 1px 0 rgba(255, 255, 255, 0.6) inset,
    0 30px 80px -45px rgba(31, 27, 22, 0.4);
  overflow: hidden;
}
/* Masthead strip — the editor chrome, with a centred printer's rule. */
.legal-editor__bar {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  padding: 0.6rem 1rem;
  border-bottom: 2px double var(--color-paper-3);
  background: var(--color-paper);
}
.legal-editor__bar .rule {
  flex: 1 1 auto;
  height: 1px;
  background: var(--color-ink);
  opacity: 0.55;
}
.legal-editor__bar .mark {
  font-family: var(--font-typewriter);
  font-size: 0.62rem;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: var(--color-ink-muted);
}
.legal-editor__bar .star {
  color: var(--color-vermilion);
  font-size: 0.8rem;
}
/* The scrollable manuscript canvas. */
.legal-editor__scroll {
  max-height: min(72vh, 760px);
  overflow-y: auto;
  padding: 2rem 1.5rem 2.5rem;
  scrollbar-width: thin;
  scrollbar-color: var(--color-paper-3) transparent;
}
@media (min-width: 768px) {
  .legal-editor__scroll {
    padding: 2.75rem 3rem 3rem;
  }
}
.legal-doc {
  max-width: 64ch;
  margin: 0 auto;
}

.doc-h2 {
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 1.4rem;
  color: var(--color-ink);
  margin: 2.4rem 0 0.6rem;
  padding-top: 1.4rem;
  border-top: 1px solid var(--color-paper-3);
  scroll-margin-top: 1rem;
}
/* The first section sits flush against the callout / intro. */
.doc-callout + .doc-h2,
.legal-doc > .doc-h2:first-child {
  margin-top: 0.4rem;
  padding-top: 0;
  border-top: none;
}
.doc-h3 {
  font-family: var(--font-display);
  font-weight: 600;
  font-size: 1.05rem;
  color: var(--color-vermilion);
  margin: 1.4rem 0 0.4rem;
}
.doc-lead {
  font-family: var(--font-serif);
  font-style: italic;
  font-size: 1.05rem;
  line-height: 1.7;
  color: var(--color-ink-light);
  margin-bottom: 1rem;
}
.doc-p {
  font-family: var(--font-serif);
  font-size: 1rem;
  line-height: 1.75;
  color: var(--color-ink);
  margin-bottom: 0.95rem;
  text-align: justify;
  hyphens: auto;
  -webkit-hyphens: auto;
}
.doc-p a {
  color: var(--color-vermilion);
  text-decoration: underline;
  text-underline-offset: 2px;
}
.doc-ul {
  margin: 0.5rem 0 1rem 1.25rem;
  list-style: none;
}
.doc-ul li {
  position: relative;
  padding-left: 1rem;
  font-family: var(--font-serif);
  font-size: 0.96rem;
  line-height: 1.7;
  color: var(--color-ink);
  margin-bottom: 0.4rem;
}
.doc-ul li::before {
  content: "\2766"; /* ❦ floral heart */
  position: absolute;
  left: -0.25rem;
  color: var(--color-vermilion);
  font-size: 0.7rem;
}
.doc-callout {
  background: var(--color-paper-soft);
  border-left: 3px solid var(--color-vermilion);
  padding: 1rem 1.25rem;
  margin: 0 0 1.25rem;
}
.doc-callout p {
  margin: 0;
  font-family: var(--font-serif);
  font-style: italic;
  font-size: 0.95rem;
  line-height: 1.65;
  color: var(--color-ink-light);
}

